import json
import boto3

def lambda_handler(event, context):
    # Example function using shared permissions
    s3_client = boto3.client('s3')
    dynamodb = boto3.resource('dynamodb')
    sns_client = boto3.client('sns')
    sqs_client = boto3.client('sqs')
    
    # S3 operations
    try:
        response = s3_client.get_object(Bucket='my-bucket', Key='test.txt')
        print("S3 Read successful")
    except Exception as e:
        print(f"S3 Error: {e}")
    
    # DynamoDB operations
    try:
        table = dynamodb.Table('my-table')
        response = table.get_item(Key={'id': '123'})
        print("DynamoDB Read successful")
    except Exception as e:
        print(f"DynamoDB Error: {e}")
    
    # SNS operations
    try:
        sns_client.publish(
            TopicArn='arn:aws:sns:us-east-1:123456789012:my-topic',
            Message='Test message'
        )
        print("SNS Publish successful")
    except Exception as e:
        print(f"SNS Error: {e}")
    
    # SQS operations
    try:
        sqs_client.send_message(
            QueueUrl='https://sqs.us-east-1.amazonaws.com/123456789012/my-queue',
            Message='Test message'
        )
        print("SQS Send successful")
    except Exception as e:
        print(f"SQS Error: {e}")
    
    return {
        'statusCode': 200,
        'body': json.dumps('All operations completed successfully')
    }